-- A query result dataset is a virtual dataset that is represented by a SQL
-- query. The raw data can be generated by inspecting the SQL query to determine
-- its dependencies, loading the dependent datasets, and then running the query
-- against them in order to "materialize" this dataset into actual raw data.
-- A "query_result" dataset can be represented by just the raw SQL query that
-- generated it. In that sense it is similar to what a View is in a database.
create table public.datasets__query_result (
  -- Primary key
  id uuid primary key default gen_random_uuid(),
  -- Dataset this metadata belongs to
  dataset_id uuid not null unique references public.datasets (id) on update cascade on delete cascade,
  -- Workspace this dataset belongs to
  workspace_id uuid not null references public.workspaces (id) on update cascade on delete cascade,
  -- Timestamp of when the dataset was created.
  created_at timestamptz not null default now(),
  -- Timestamp of when the dataset was last updated.
  updated_at timestamptz not null default now(),
  -- The query that was used to generate the dataset
  raw_sql text not null
);

-- Enable row level security
alter table public.datasets__query_result enable row level security;

-- Policies
create policy "User can select datasets__query_result in their workspace" on public.datasets__query_result for
select
  to authenticated using (
    public.datasets__query_result.workspace_id = any (
      array(
        select
          public.util__get_auth_user_workspaces ()
      )
    )
  );

create policy "User can insert datasets__query_result in their workspace" on public.datasets__query_result for insert to authenticated
with
  check (
    public.datasets__query_result.workspace_id = any (
      array(
        select
          public.util__get_auth_user_workspaces ()
      )
    )
  );

create policy "User can update datasets__query_result in their workspace" on public.datasets__query_result
for update
  to authenticated using (
    public.datasets__query_result.workspace_id = any (
      array(
        select
          public.util__get_auth_user_workspaces ()
      )
    )
  )
with
  check (
    -- Updated values must still be in the auth user's workspace
    public.datasets__query_result.workspace_id = any (
      array(
        select
          public.util__get_auth_user_workspaces ()
      )
    )
  );

create policy "User can delete datasets__query_result in their workspace" on public.datasets__query_result for delete to authenticated using (
  public.datasets__query_result.workspace_id = any (
    array(
      select
        public.util__get_auth_user_workspaces ()
    )
  )
);

/**
 * Trigger the `updated_at` update
 */
create trigger tr_datasets__query_result__set_updated_at before
update on public.datasets__query_result for each row
execute function public.util__set_updated_at ();
